import osimport matplotlib.pyplot as pltfrom mpl_toolkits.mplot3d import Axes3Dskiplines = 3mol_id = 0pdb_folder = os.path.join("PDB", "mergePDB")pdb_filenames = os.listdir(pdb_folder)timeframes = sorted(set([int(filename.split(".")[0])                          for filename in pdb_filenames]))times = []x = []y = []z = []for timeframe in timeframes:    times.append(timeframe)    pdb_filename = f"{timeframe}.pdb"    pdb_path = os.path.join(pdb_folder, pdb_filename)        with open(pdb_path, "r") as pdb_file:        # skip the first 3 lines                for _ in range(skiplines):            pdb_file.readline()        # then read in line by line        # for each line, parse the type and id until found "COM" and         # the wanted mol_id        # each line has this format:        #ATOM      1  COM   A    0      116.692 505.928 869.555     0     0CL        for line in pdb_file:            atom_type = line[13:16].strip()            mol_idx = int(line[20:25])            x_coord = float(line[30:38])            y_coord = float(line[38:46])            z_coord = float(line[46:54])                        if atom_type == "COM" and mol_idx == mol_id:                x.append(x_coord)                y.append(y_coord)                z.append(z_coord)                breakfig1 = plt.figure()ax1 = fig1.add_subplot(111, projection="3d")ax1.plot(x, y, z)ax1.set_xlabel("X")ax1.set_ylabel("Y")ax1.set_zlabel("Z")ax1.set_title("Molecule Trajectory in 3D")fig2, (ax2, ax3, ax4) = plt.subplots(3, 1, sharex=True)ax2.plot(times, x)ax2.set_ylabel("X")ax3.plot(times, y)ax3.set_ylabel("Y")ax4.plot(times, z)ax4.set_ylabel("Z")ax4.set_xlabel("Time (frame)")plt.show()        